with:
  if obj in subject_map:
                      # Build a concise relative clause for the linked entity using its most releva...
                      rel_parts = []
                      for p2, o2 in subject_map[obj]:
                          # Prefer managerial or venue information for sports entities
                          if p2 == "manager":
                              rel_parts.append(f"is managed by {o2}")
                          elif p2 == "coach":
                              rel_parts.append(f"is coached by {o2}")
                          elif p2 == "ground":
                              rel_parts.append(f"has home ground {o2}")
                          elif p2 == "stadium":
                              rel_parts.append(f"plays at {o2}")
                          elif p2 == "city":
                              rel_parts.append(f"is based in {o2}")
                          elif p2 == "country":
                              rel_parts.append(f"is located in {o2}")
                      if rel_parts:
                          # Use “which” for a single clause or “which … and …” for multiple
                          if len(rel_parts) == 1:
                              phrase += f", which {rel_parts[0]}"
                          else:
                              phrase += f", which {' and '.join(rel_parts)}"
